"use client";

import {
  forwardRef,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import {
  DndContext,
  KeyboardSensor,
  PointerSensor,
  closestCenter,
  useSensor,
  useSensors,
  type Announcements,
  type DragEndEvent,
} from "@dnd-kit/core";
import { arrayMove, sortableKeyboardCoordinates } from "@dnd-kit/sortable";
import { AlertCircle, X } from "lucide-react";
import { cn } from "@/lib/utils";
import {
  DEFAULT_CAROUSEL_LABELS,
  type MediaCarouselEditor01Handle,
  type MediaCarouselEditor01Props,
} from "./types";
import { useCarouselState } from "./hooks/use-carousel-state";
import { filesToItems } from "./lib/file-intake";
import { clampSources } from "./lib/clamp-sources";
import { aspectToCss, resolveAspect } from "./lib/aspect";
import { MediaDropzone } from "./parts/media-dropzone";
import { PreviewRail } from "./parts/preview-rail";
import { MainPreview } from "./parts/main-preview";
import { EditPanel } from "./parts/edit-panel";

/**
 * media-carousel-editor-01 — a multi-item media composer (Instagram-feed-post
 * semantics): drag-drop / browse one-or-more mixed photo+video files into an
 * ordered, reorderable rail with a main preview, and edit any item through a
 * single shared `media-editor-01` instance (loaded serially, never N at once).
 * Composes media-editor-01 without modifying it.
 */
function MediaCarouselEditor01Impl(
  props: MediaCarouselEditor01Props,
  ref: React.Ref<MediaCarouselEditor01Handle>,
) {
  const {
    value,
    defaultValue,
    onChange,
    maxItems = 10,
    maxFileSizeMb = 50,
    accept,
    sources,
    aspect = "auto",
    editorProps,
    labels: labelOverrides,
    className,
    revokeOnUnmount,
    onItemAdd,
    onItemRemove,
    onReorder,
    onSelect,
    onEditOpen,
    onEditApply,
    onEditCancel,
    onValidationError,
    onMaxItemsExceeded,
  } = props;

  const labels = useMemo(
    () => ({ ...DEFAULT_CAROUSEL_LABELS, ...labelOverrides }),
    [labelOverrides],
  );
  const acceptKinds = useMemo(
    () => accept ?? ["image" as const, "video" as const],
    [accept],
  );
  // v0.1: "library" is clamped out — intake is upload-only (drop / browse).
  const uploadEnabled = useMemo(
    () => clampSources(sources).includes("upload"),
    [sources],
  );

  const [ingesting, setIngesting] = useState(false);
  const [errors, setErrors] = useState<string[]>([]);
  const [announce, setAnnounce] = useState("");

  const fillTemplate = (tpl: string) => tpl.replace("{max}", String(maxItems));

  const state = useCarouselState({
    value,
    defaultValue,
    onChange,
    maxItems,
    revokeOnUnmount,
    onItemAdd,
    onItemRemove: (id) => {
      onItemRemove?.(id);
      setAnnounce(labels.remove);
    },
    onReorder: (items) => {
      onReorder?.(items);
      setAnnounce(labels.reorderHint);
    },
    onSelect,
    onEditOpen,
    onEditApply,
    onEditCancel,
    onMaxItemsExceeded: (attempted, max) => {
      onMaxItemsExceeded?.(attempted, max);
      const msg = fillTemplate(labels.maxReached);
      setErrors((prev) => (prev.includes(msg) ? prev : [...prev, msg]));
      setAnnounce(msg);
    },
  });

  // Latest items for stable async reads (file intake + imperative handle).
  const itemsRef = useRef(state.items);
  useEffect(() => {
    itemsRef.current = state.items;
  });

  const resolvedAspect = useMemo(
    () => resolveAspect(state.items, aspect),
    [state.items, aspect],
  );

  const addFiles = async (files: File[] | FileList) => {
    setErrors([]);
    setIngesting(true);
    try {
      const res = await filesToItems(files, {
        accept: acceptKinds,
        maxFileSizeMb,
      });
      res.errors.forEach((err) => onValidationError?.(err));
      if (res.errors.length > 0) {
        setErrors((prev) => [...prev, ...res.errors.map((e) => e.message)]);
      }
      // addItems caps to maxItems synchronously + fires onMaxItemsExceeded.
      if (res.items.length > 0) {
        state.addItems(res.items);
        setAnnounce(
          `${res.items.length} item${res.items.length === 1 ? "" : "s"} added`,
        );
      }
    } finally {
      setIngesting(false);
    }
  };

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 4 } }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    }),
  );

  const dndAnnouncements: Announcements = useMemo(() => {
    const pos = (id: string | number) =>
      itemsRef.current.findIndex((it) => it.id === id) + 1;
    const total = () => itemsRef.current.length;
    return {
      onDragStart: ({ active }) => `Picked up item ${pos(active.id)}.`,
      onDragOver: ({ active, over }) =>
        over ? `Item ${pos(active.id)} over position ${pos(over.id)}.` : "",
      onDragEnd: ({ active, over }) =>
        over
          ? `Item dropped at position ${pos(over.id)} of ${total()}.`
          : `Item ${pos(active.id)} dropped.`,
      onDragCancel: ({ active }) =>
        `Reorder cancelled; item ${pos(active.id)} returned.`,
    };
  }, []);

  const onDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    if (!over || active.id === over.id) return;
    const items = itemsRef.current;
    const oldIndex = items.findIndex((it) => it.id === active.id);
    const newIndex = items.findIndex((it) => it.id === over.id);
    if (oldIndex < 0 || newIndex < 0) return;
    state.reorder(arrayMove(items, oldIndex, newIndex));
  };

  useImperativeHandle(
    ref,
    (): MediaCarouselEditor01Handle => ({
      getItems: () => itemsRef.current.map((it) => ({ ...it })),
      export: async () => itemsRef.current.map((it) => ({ ...it })),
      addFiles,
      removeItem: state.removeItem,
      select: state.select,
      openEditor: state.openEditor,
      reset: state.reset,
    }),
    // addFiles is recreated each render (intentional); the rest are stable.
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [state.removeItem, state.select, state.openEditor, state.reset],
  );

  const isEmpty = state.items.length === 0;
  const isEditing = state.editingId !== null && state.editingItem !== null;
  const canAddMore = uploadEnabled && state.items.length < maxItems;

  return (
    <div className={cn("flex flex-col gap-3", className)}>
      {isEmpty ? (
        uploadEnabled ? (
          <MediaDropzone
            variant="empty"
            accept={acceptKinds}
            maxItems={maxItems}
            busy={ingesting}
            labels={labels}
            onFiles={addFiles}
          />
        ) : null
      ) : isEditing ? (
        <EditPanel
          key={state.editingItem!.id}
          item={state.editingItem!}
          aspect={resolvedAspect}
          editorProps={editorProps}
          labels={labels}
          onApply={state.applyEdit}
          onCancel={state.cancelEdit}
        />
      ) : (
        <MainPreview
          item={state.selectedItem}
          aspectCss={aspectToCss(resolvedAspect)}
          canEdit={state.selectedItem?.kind === "image"}
          labels={labels}
          onEdit={() =>
            state.selectedItem && state.openEditor(state.selectedItem.id)
          }
        />
      )}

      {errors.length > 0 ? (
        <div
          role="alert"
          className="flex items-start gap-2 rounded-md border border-destructive/40 bg-destructive/10 px-3 py-2 text-sm text-foreground"
        >
          <AlertCircle
            className="mt-0.5 size-4 shrink-0 text-destructive"
            aria-hidden
          />
          <ul className="flex-1 space-y-0.5">
            {errors.map((msg, i) => (
              <li key={i}>{msg}</li>
            ))}
          </ul>
          <button
            type="button"
            aria-label="Dismiss"
            onClick={() => setErrors([])}
            className="shrink-0 rounded p-0.5 text-muted-foreground transition hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          >
            <X className="size-4" aria-hidden />
          </button>
        </div>
      ) : null}

      {!isEmpty ? (
        <DndContext
          sensors={sensors}
          collisionDetection={closestCenter}
          accessibility={{ announcements: dndAnnouncements }}
          onDragEnd={onDragEnd}
        >
          <PreviewRail
            items={state.items}
            selectedId={state.selectedId}
            disabled={isEditing}
            canAddMore={canAddMore}
            busy={ingesting}
            accept={acceptKinds}
            maxItems={maxItems}
            labels={labels}
            onSelect={state.select}
            onRemove={state.removeItem}
            onFiles={addFiles}
          />
        </DndContext>
      ) : null}

      <output aria-live="polite" className="sr-only">
        {announce}
      </output>
    </div>
  );
}

export const MediaCarouselEditor01 = forwardRef(MediaCarouselEditor01Impl);
MediaCarouselEditor01.displayName = "MediaCarouselEditor01";

// ─── Tail type re-exports (cross-procomp consumers) ──────────────────────────
// Procomps that compose media-carousel-editor-01 must import these types from
// THIS component-file path, not `./types`: the shadcn path rewriter resolves a
// barrel/directory import to this `.tsx` file but mangles `/types` subpaths
// (F-01). Mirrors media-editor-01's tail band.
export type {
  MediaCarouselItem,
  MediaKind,
  MediaCarouselSource,
  MediaCarouselError,
  MediaCarouselEditor01Props,
  MediaCarouselEditor01Handle,
  MediaCarouselEditor01Labels,
} from "./types";

export { MediaCarouselEditor01 } from "./media-carousel-editor-01";

export type {
  MediaCarouselItem,
  MediaKind,
  MediaCarouselSource,
  MediaCarouselError,
  MediaCarouselEditor01Props,
  MediaCarouselEditor01Handle,
  MediaCarouselEditor01Labels,
} from "./types";
export { DEFAULT_CAROUSEL_LABELS } from "./types";

// Headless state primitive — for consumers that recompose the surface from the
// parts below and need the model (items / selection / editing / URL lifecycle).
export { useCarouselState } from "./hooks/use-carousel-state";
export type {
  UseCarouselStateOptions,
  UseCarouselStateResult,
  CarouselStateCallbacks,
  ApplyEditPatch,
} from "./hooks/use-carousel-state";

// Public parts — for sealed-folder consumers that want to recompose the surface.
export { MediaDropzone } from "./parts/media-dropzone";
export type { MediaDropzoneProps } from "./parts/media-dropzone";
export { PreviewRail } from "./parts/preview-rail";
export type { PreviewRailProps } from "./parts/preview-rail";
export { RailThumb } from "./parts/rail-thumb";
export type { RailThumbProps } from "./parts/rail-thumb";
export { MainPreview } from "./parts/main-preview";
export type { MainPreviewProps } from "./parts/main-preview";
export { EditPanel } from "./parts/edit-panel";
export type { EditPanelProps } from "./parts/edit-panel";

import type {
  AspectRatio,
  ExportMetadata,
  InitialSource,
  MediaEditor01Handle,
  MediaEditor01Props,
  MediaEditorState,
} from "@/registry/components/media/media-editor-01/media-editor-01";
// ↑ The SOLE cross-procomp module surface (F-01). Types come from the .tsx
//   entry's tail re-export band — NOT a `/types` subpath (the rewriter mangles
//   that). `ValidationError` is NOT in that band, so the carousel defines its
//   own `MediaCarouselError` below and media-editor-01 stays untouched.

// Re-export the media-editor-01 types this procomp surfaces, so sibling files
// pull them from the local types barrel and the external module path stays in
// as few files as possible.
export type {
  AspectRatio,
  ExportMetadata,
  InitialSource,
  MediaEditor01Handle,
  MediaEditorState,
};

export type MediaKind = "image" | "video";
export type MediaCarouselSource = "upload" | "library"; // "library" clamped in v0.1

/**
 * Own error type — media-editor-01's `ValidationError` is not re-exported from
 * its `.tsx` entry, and we keep media-editor-01 untouched. Structurally aligned.
 */
export interface MediaCarouselError {
  // The cap has its own `onMaxItemsExceeded` channel — this type is per-file
  // validation only.
  kind: "unsupported-type" | "file-too-large";
  message: string;
  file?: File;
}

/**
 * One item in the carousel. `url` is the CURRENT displayable source — an object
 * URL for local/edited media, or a remote URL for re-edit seeds. After an
 * edit-apply, `url`/`blob` reflect the flattened export and `editorState`
 * retains the editable layers so a re-open can `loadState` them (photo path).
 */
export interface MediaCarouselItem {
  id: string;
  kind: MediaKind;
  url: string;
  /** Present for local/edited media; absent for a remote-only re-edit seed. */
  blob?: Blob;
  /** Present once edited (photo path; `videoBlob` is always nulled). */
  editorState?: MediaEditorState;
  /** From the last `export()` of this item. */
  exportMeta?: ExportMetadata;
  width?: number;
  height?: number;
  fileName?: string;
}

export interface MediaCarouselEditor01Labels {
  dropzoneTitle?: string;
  dropzoneBrowse?: string;
  dropzoneHint?: string;
  addMore?: string;
  edit?: string;
  editDone?: string;
  editCancel?: string;
  editSaving?: string;
  editError?: string;
  remove?: string;
  reorderHint?: string;
  maxReached?: string;
  videoNotEditable?: string;
  finishEditingHint?: string;
  /** Template with `{n}` / `{total}` / `{kind}`. */
  itemAria?: string;
}

export const DEFAULT_CAROUSEL_LABELS: Required<MediaCarouselEditor01Labels> = {
  dropzoneTitle: "Drag photos & videos here",
  dropzoneBrowse: "Browse",
  dropzoneHint: "or drop up to {max} files",
  addMore: "Add more",
  edit: "Edit",
  editDone: "Done",
  editCancel: "Cancel",
  editSaving: "Saving…",
  editError: "Couldn't save your edit. Try again.",
  remove: "Remove",
  reorderHint: "Drag to reorder",
  maxReached: "Maximum {max} items reached",
  videoNotEditable: "Video editing arrives in v0.2",
  finishEditingHint: "Finish editing to reorder or add media",
  itemAria: "Media item {n} of {total}, {kind}",
};

export interface MediaCarouselEditor01Props {
  // value
  value?: MediaCarouselItem[];
  defaultValue?: MediaCarouselItem[];
  onChange?: (items: MediaCarouselItem[]) => void;

  // capability dials
  maxItems?: number; // default 10
  maxFileSizeMb?: number; // default 50 (mirrors media-editor-01)
  accept?: MediaKind[]; // default ["image","video"]
  sources?: MediaCarouselSource[]; // default ["upload"]; "library" clamped/no-op
  aspect?: AspectRatio | "auto"; // default "auto" → derive from item 1 dims

  // forwarded subset of media-editor-01 dials (edit panel). Crop aspect is OWNED
  // by `aspect` here (shared-aspect guarantee) — deliberately not in this Pick.
  editorProps?: Pick<
    MediaEditor01Props,
    "enabledTools" | "stickers" | "fonts" | "colorPresets" | "filterPresets" | "labels"
  >;

  labels?: Partial<MediaCarouselEditor01Labels>;
  className?: string;
  /**
   * Revoke object URLs this component created when it unmounts. Default true.
   * Set false ONLY when a host preserves the live items across remounts and
   * takes over final cleanup (e.g. content-composer's carousel cache).
   */
  revokeOnUnmount?: boolean;

  // events
  onItemAdd?: (item: MediaCarouselItem) => void;
  onItemRemove?: (id: string) => void;
  onReorder?: (items: MediaCarouselItem[]) => void;
  onSelect?: (id: string | null) => void;
  onEditOpen?: (id: string) => void;
  onEditApply?: (item: MediaCarouselItem) => void;
  onEditCancel?: (id: string) => void;
  onValidationError?: (error: MediaCarouselError) => void;
  onMaxItemsExceeded?: (attempted: number, max: number) => void;
}

export interface MediaCarouselEditor01Handle {
  getItems: () => MediaCarouselItem[];
  /**
   * Pull-only: resolves a defensive copy of the COMMITTED ordered items (already
   * flattened on edit-apply). An open-but-unapplied edit is NOT included — the
   * host should gate publish while editing.
   */
  export: () => Promise<MediaCarouselItem[]>;
  addFiles: (files: File[] | FileList) => void;
  removeItem: (id: string) => void;
  select: (id: string | null) => void;
  openEditor: (id: string) => void;
  /** Revoke all owned object URLs; clears items. Also auto-runs on unmount. */
  reset: () => void;
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type { ExportMetadata, MediaCarouselItem, MediaEditorState } from "../types";
import { useControllableState } from "./use-controllable-state";

export interface CarouselStateCallbacks {
  onItemAdd?: (item: MediaCarouselItem) => void;
  onItemRemove?: (id: string) => void;
  onReorder?: (items: MediaCarouselItem[]) => void;
  onSelect?: (id: string | null) => void;
  onEditOpen?: (id: string) => void;
  onEditApply?: (item: MediaCarouselItem) => void;
  onEditCancel?: (id: string) => void;
  onMaxItemsExceeded?: (attempted: number, max: number) => void;
}

export interface UseCarouselStateOptions extends CarouselStateCallbacks {
  value?: MediaCarouselItem[];
  defaultValue?: MediaCarouselItem[];
  onChange?: (items: MediaCarouselItem[]) => void;
  maxItems: number;
  /**
   * Revoke owned object URLs when the component unmounts. Default true. A host
   * that persists the live items across remounts (e.g. content-composer's
   * carousel cache) sets this false and owns the final cleanup itself.
   */
  revokeOnUnmount?: boolean;
}

export interface ApplyEditPatch {
  url: string;
  blob?: Blob;
  editorState?: MediaEditorState;
  exportMeta?: ExportMetadata;
  width?: number;
  height?: number;
}

export interface UseCarouselStateResult {
  items: MediaCarouselItem[];
  selectedId: string | null;
  editingId: string | null;
  selectedItem: MediaCarouselItem | null;
  editingItem: MediaCarouselItem | null;
  addItems: (next: MediaCarouselItem[]) => void;
  removeItem: (id: string) => void;
  reorder: (next: MediaCarouselItem[]) => void;
  select: (id: string | null) => void;
  openEditor: (id: string) => void;
  cancelEdit: () => void;
  applyEdit: (id: string, patch: ApplyEditPatch) => void;
  reset: () => void;
}

/** Only object URLs we created are ours to revoke; remote/consumer URLs aren't. */
function isOwnable(url: string): boolean {
  return url.startsWith("blob:");
}

/**
 * Owns the carousel model: a controllable `items` array (value/defaultValue/
 * onChange) plus internal `selectedId` / `editingId`, and the object-URL
 * lifecycle. `itemsRef` is updated SYNCHRONOUSLY inside every mutator (not via an
 * effect) so async/batched intakes can't read a stale base. An orphan-revoke
 * effect catches URLs dropped by any path — including a wholesale controlled
 * `value` swap (e.g. the host's `loadValue`) that bypasses removeItem.
 */
export function useCarouselState(
  opts: UseCarouselStateOptions,
): UseCarouselStateResult {
  const { maxItems, revokeOnUnmount = true } = opts;

  const [items, setItemsRaw] = useControllableState<MediaCarouselItem[]>({
    value: opts.value,
    defaultValue: opts.defaultValue ?? [],
    onChange: opts.onChange,
    componentName: "MediaCarouselEditor01",
    valuePropName: "value",
  });
  const [rawSelectedId, setSelectedId] = useState<string | null>(
    opts.value?.[0]?.id ?? opts.defaultValue?.[0]?.id ?? null,
  );
  const [editingId, setEditingId] = useState<string | null>(null);

  const selectedId =
    rawSelectedId != null && items.some((it) => it.id === rawSelectedId)
      ? rawSelectedId
      : (items[0]?.id ?? null);

  const cbRef = useRef<CarouselStateCallbacks>(opts);
  useEffect(() => {
    cbRef.current = opts;
  });

  // itemsRef tracks committed render state; mutators below ALSO write it
  // synchronously so a second mutation in the same tick reads the latest base.
  const itemsRef = useRef(items);
  const selectedIdRef = useRef(selectedId);
  const editingIdRef = useRef(editingId);
  useEffect(() => {
    itemsRef.current = items;
    selectedIdRef.current = selectedId;
    editingIdRef.current = editingId;
  });

  /** Synchronous-ref write + state set, so chained mutators compose correctly. */
  const setItems = useCallback(
    (next: MediaCarouselItem[]) => {
      itemsRef.current = next;
      setItemsRaw(next);
    },
    [setItemsRaw],
  );

  // Object-URL ownership.
  const ownedUrls = useRef<Set<string>>(new Set());
  const revoke = useCallback((url: string) => {
    if (ownedUrls.current.has(url)) {
      URL.revokeObjectURL(url);
      ownedUrls.current.delete(url);
    }
  }, []);

  // Catch-all: revoke any owned URL no longer present in items — including
  // drops via a controlled `value` swap that never went through removeItem.
  useEffect(() => {
    const present = new Set(items.map((it) => it.url));
    ownedUrls.current.forEach((u) => {
      if (!present.has(u)) {
        URL.revokeObjectURL(u);
        ownedUrls.current.delete(u);
      }
    });
  }, [items]);

  useEffect(() => {
    const owned = ownedUrls.current;
    return () => {
      if (!revokeOnUnmount) return;
      owned.forEach((u) => URL.revokeObjectURL(u));
      owned.clear();
    };
  }, [revokeOnUnmount]);

  const addItems = useCallback(
    (incoming: MediaCarouselItem[]) => {
      if (incoming.length === 0) return;
      // Cap synchronously against the latest items (race-safe).
      const room = Math.max(0, maxItems - itemsRef.current.length);
      const toAdd = incoming.slice(0, room);
      const dropped = incoming.slice(room);
      // Revoke object URLs of items we won't keep (intake created them).
      dropped.forEach((it) => {
        if (isOwnable(it.url)) URL.revokeObjectURL(it.url);
      });
      if (toAdd.length > 0) {
        toAdd.forEach((it) => {
          if (isOwnable(it.url)) ownedUrls.current.add(it.url);
        });
        setItems([...itemsRef.current, ...toAdd]);
        toAdd.forEach((it) => cbRef.current.onItemAdd?.(it));
      }
      if (dropped.length > 0) {
        cbRef.current.onMaxItemsExceeded?.(
          itemsRef.current.length + dropped.length,
          maxItems,
        );
      }
    },
    [maxItems, setItems],
  );

  const removeItem = useCallback(
    (id: string) => {
      const cur = itemsRef.current;
      const idx = cur.findIndex((it) => it.id === id);
      if (idx < 0) return;
      revoke(cur[idx].url);
      const next = cur.filter((it) => it.id !== id);
      setItems(next);
      cbRef.current.onItemRemove?.(id);
      if (selectedIdRef.current === id) {
        const neighbor = next[Math.min(idx, next.length - 1)] ?? null;
        const nid = neighbor?.id ?? null;
        setSelectedId(nid);
        cbRef.current.onSelect?.(nid);
      }
      if (editingIdRef.current === id) {
        setEditingId(null);
        cbRef.current.onEditCancel?.(id);
      }
    },
    [revoke, setItems],
  );

  const reorder = useCallback(
    (next: MediaCarouselItem[]) => {
      setItems(next);
      cbRef.current.onReorder?.(next);
    },
    [setItems],
  );

  const select = useCallback((id: string | null) => {
    setSelectedId(id);
    cbRef.current.onSelect?.(id);
  }, []);

  const openEditor = useCallback((id: string) => {
    setSelectedId(id);
    setEditingId(id);
    cbRef.current.onEditOpen?.(id);
  }, []);

  const cancelEdit = useCallback(() => {
    const id = editingIdRef.current;
    if (id == null) return;
    setEditingId(null);
    cbRef.current.onEditCancel?.(id);
  }, []);

  const applyEdit = useCallback(
    (id: string, patch: ApplyEditPatch) => {
      const cur = itemsRef.current;
      const idx = cur.findIndex((it) => it.id === id);
      if (idx < 0) return;
      const prev = cur[idx];
      if (prev.url !== patch.url) revoke(prev.url);
      if (isOwnable(patch.url)) ownedUrls.current.add(patch.url);
      const updated: MediaCarouselItem = {
        ...prev,
        url: patch.url,
        blob: patch.blob ?? prev.blob,
        editorState: patch.editorState ?? prev.editorState,
        exportMeta: patch.exportMeta ?? prev.exportMeta,
        width: patch.width ?? prev.width,
        height: patch.height ?? prev.height,
      };
      setItems(cur.map((it, i) => (i === idx ? updated : it)));
      setEditingId(null);
      cbRef.current.onEditApply?.(updated);
    },
    [revoke, setItems],
  );

  const reset = useCallback(() => {
    ownedUrls.current.forEach((u) => URL.revokeObjectURL(u));
    ownedUrls.current.clear();
    setItems([]);
    setSelectedId(null);
    setEditingId(null);
  }, [setItems]);

  const selectedItem = items.find((it) => it.id === selectedId) ?? null;
  const editingItem = items.find((it) => it.id === editingId) ?? null;

  return {
    items,
    selectedId,
    editingId,
    selectedItem,
    editingItem,
    addItems,
    removeItem,
    reorder,
    select,
    openEditor,
    cancelEdit,
    applyEdit,
    reset,
  };
}

import { useCallback, useEffect, useRef, useState } from "react";

interface UseControllableStateOpts<T> {
  /** Controlled value. When provided, state is fully controlled by parent. */
  value?: T;
  /** Initial value for uncontrolled mode. */
  defaultValue: T;
  /** Fires on every state change (both modes). */
  onChange?: (next: T) => void;
  /** Component name used in dev warnings. */
  componentName: string;
  /** Prop name used in dev warnings (e.g., `"value"`). */
  valuePropName: string;
}

/**
 * Controlled+uncontrolled state-machine helper. Sealed local copy of the
 * library's standard generic (navigation/account-switcher-01 + code-block) —
 * registry components can't share an app-level util beyond `@/lib/utils`, so
 * each procomp seals its own copy.
 *
 *   - Locks the controlled/uncontrolled mode based on the FIRST render's
 *     `value` and dev-warns when consumers flip modes mid-life.
 *   - Dev-warns when controlled mode is used without an `onChange` handler.
 *
 * Both warns tree-shake out of prod bundles.
 *
 * Internal helper — not exported from the procomp's public API.
 */
export function useControllableState<T>({
  value,
  defaultValue,
  onChange,
  componentName,
  valuePropName,
}: UseControllableStateOpts<T>): readonly [T, (next: T) => void] {
  const [internal, setInternal] = useState<T>(defaultValue);
  const isControlled = value !== undefined;
  const onChangeRef = useRef(onChange);
  useEffect(() => {
    onChangeRef.current = onChange;
  });

  const wasControlledRef = useRef(isControlled);
  useEffect(() => {
    if (process.env.NODE_ENV === "production") return;
    if (wasControlledRef.current !== isControlled) {
      console.warn(
        `[${componentName}] \`${valuePropName}\` switched from ${
          wasControlledRef.current ? "controlled" : "uncontrolled"
        } to ${
          isControlled ? "controlled" : "uncontrolled"
        } mode. Components should not switch modes mid-life; pick one at mount.`,
      );
      wasControlledRef.current = isControlled;
    }
  }, [isControlled, componentName, valuePropName]);

  useEffect(() => {
    if (process.env.NODE_ENV === "production") return;
    if (isControlled && !onChangeRef.current) {
      const capitalized =
        valuePropName.charAt(0).toUpperCase() + valuePropName.slice(1);
      console.warn(
        `[${componentName}] \`${valuePropName}\` is controlled but no onChange handler was provided. ` +
          `State will appear frozen. Pass \`on${capitalized}Change\` ` +
          `(or use the uncontrolled variant by passing \`default${capitalized}\` instead).`,
      );
    }
  }, [isControlled, componentName, valuePropName]);

  const current = isControlled ? (value as T) : internal;

  const set = useCallback(
    (next: T) => {
      if (!isControlled) setInternal(next);
      onChangeRef.current?.(next);
    },
    [isControlled],
  );

  return [current, set] as const;
}

import type { AspectRatio, MediaCarouselItem } from "../types";

const RATIOS: { aspect: Exclude<AspectRatio, "free">; value: number }[] = [
  { aspect: "9:16", value: 9 / 16 },
  { aspect: "4:5", value: 4 / 5 },
  { aspect: "1:1", value: 1 },
  { aspect: "16:9", value: 16 / 9 },
];

/**
 * Resolve the carousel's shared aspect (Instagram behaviour): an explicit prop
 * wins; `"auto"` derives from item 1's natural ratio (nearest of the four
 * standard ratios); falls back to `"1:1"` until item 1's dimensions are known.
 */
export function resolveAspect(
  items: MediaCarouselItem[],
  prop: AspectRatio | "auto",
): AspectRatio {
  if (prop !== "auto") return prop;
  const first = items[0];
  if (!first?.width || !first?.height) return "1:1";
  const ratio = first.width / first.height;
  let best: Exclude<AspectRatio, "free"> = "1:1";
  let bestDiff = Infinity;
  for (const cand of RATIOS) {
    const diff = Math.abs(cand.value - ratio);
    if (diff < bestDiff) {
      bestDiff = diff;
      best = cand.aspect;
    }
  }
  return best;
}

/**
 * CSS `aspect-ratio` value for a frame. `"free"` falls back to a 1:1 frame so the
 * rail + main preview keep a consistent footprint.
 */
export function aspectToCss(aspect: AspectRatio): string {
  switch (aspect) {
    case "9:16":
      return "9 / 16";
    case "4:5":
      return "4 / 5";
    case "16:9":
      return "16 / 9";
    case "1:1":
    case "free":
    default:
      return "1 / 1";
  }
}

import type { MediaCarouselSource } from "../types";

/**
 * `"library"` is declared for forward-compat (pick from existing backend media)
 * but has no implementation in v0.1 — clamp it out so a config that lists it
 * stays valid with no crash and no cosmetic leak (mirrors content-composer-01's
 * media-source clamp). Always resolves to a non-empty source list.
 */
export function clampSources(
  sources: MediaCarouselSource[] | undefined,
): MediaCarouselSource[] {
  const base = sources && sources.length > 0 ? sources : ["upload"];
  const clamped = base.filter((s) => s === "upload");
  return clamped.length > 0 ? clamped : ["upload"];
}

import type { MediaCarouselError, MediaCarouselItem, MediaKind } from "../types";
import { validateMediaFile } from "./validate-media-file";

// Per-module-load random prefix so the counter fallback can't collide with ids
// reconstructed from a prior draft after a navigation re-evaluates the module.
const ID_PREFIX = `mci-${Math.floor(Math.random() * 1e9).toString(36)}`;
let idCounter = 0;
function nextId(): string {
  if (typeof crypto !== "undefined" && "randomUUID" in crypto) {
    return crypto.randomUUID();
  }
  return `${ID_PREFIX}-${(idCounter++).toString(36)}`;
}

function readImageDims(url: string): Promise<{ width: number; height: number }> {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () =>
      resolve({ width: img.naturalWidth, height: img.naturalHeight });
    img.onerror = () => resolve({ width: 0, height: 0 });
    img.src = url;
  });
}

function readVideoDims(url: string): Promise<{ width: number; height: number }> {
  return new Promise((resolve) => {
    const video = document.createElement("video");
    video.preload = "metadata";
    video.onloadedmetadata = () =>
      resolve({ width: video.videoWidth, height: video.videoHeight });
    video.onerror = () => resolve({ width: 0, height: 0 });
    video.src = url;
  });
}

export interface FilesToItemsOptions {
  accept: MediaKind[];
  maxFileSizeMb: number;
}

export interface FilesToItemsResult {
  items: MediaCarouselItem[];
  errors: MediaCarouselError[];
}

/**
 * Validate + ingest dropped/picked files into `MediaCarouselItem`s. Creates
 * object URLs and reads natural dimensions (async) so the resolved aspect is
 * correct on first paint. The `maxItems` cap is enforced downstream in the
 * state hook (`addItems`), synchronously against the latest items — so two rapid
 * drops can't each compute room against a stale count.
 */
export async function filesToItems(
  fileList: File[] | FileList,
  opts: FilesToItemsOptions,
): Promise<FilesToItemsResult> {
  const files = Array.from(fileList);
  const errors: MediaCarouselError[] = [];
  const accepted: File[] = [];

  for (const file of files) {
    const err = validateMediaFile(file, opts.maxFileSizeMb, opts.accept);
    if (err) {
      errors.push(err);
      continue;
    }
    accepted.push(file);
  }

  const items = await Promise.all(
    accepted.map(async (file): Promise<MediaCarouselItem> => {
      const kind: MediaKind = file.type.startsWith("video/")
        ? "video"
        : "image";
      const url = URL.createObjectURL(file);
      const dims =
        kind === "image" ? await readImageDims(url) : await readVideoDims(url);
      return {
        id: nextId(),
        kind,
        url,
        blob: file,
        fileName: file.name,
        width: dims.width || undefined,
        height: dims.height || undefined,
      };
    }),
  );

  return { items, errors };
}

import type { MediaCarouselError, MediaKind } from "../types";

/**
 * Local reimplementation of media-editor-01's `validateGalleryFile` — type +
 * size check, plus an `accept` gate. Kept local (NOT imported) to hold the
 * cross-procomp surface to one module (F-01) and keep media-editor-01 untouched.
 */
export function validateMediaFile(
  file: File,
  maxFileSizeMb: number,
  accept: MediaKind[],
): MediaCarouselError | null {
  const isImage = file.type.startsWith("image/");
  const isVideo = file.type.startsWith("video/");
  const kind: MediaKind | null = isImage ? "image" : isVideo ? "video" : null;

  if (!kind) {
    return {
      kind: "unsupported-type",
      message: `Unsupported file type: ${file.type || "unknown"}`,
      file,
    };
  }
  if (!accept.includes(kind)) {
    return {
      kind: "unsupported-type",
      message: `${kind === "image" ? "Image" : "Video"} files are not accepted here.`,
      file,
    };
  }
  const maxBytes = maxFileSizeMb * 1024 * 1024;
  if (file.size > maxBytes) {
    return {
      kind: "file-too-large",
      message: `File is ${(file.size / 1024 / 1024).toFixed(1)} MB — maximum is ${maxFileSizeMb} MB.`,
      file,
    };
  }
  return null;
}

