      <div
        className={cn(
          "flex items-center gap-2 p-1 transition-opacity",
          disabled && "pointer-events-none opacity-60",
        )}
      >
        <SortableContext
          items={items.map((it) => it.id)}
          strategy={horizontalListSortingStrategy}
        >
          {items.map((item, i) => (
