              item={item}
              index={i}
              total={items.length}
              selected={item.id === selectedId}
              disabled={disabled}
              labels={labels}
              onSelect={onSelect}
              onRemove={onRemove}
            />
          ))}
        </SortableContext>
        {canAddMore && !disabled ? (
          <MediaDropzone
            variant="add-more"
            accept={accept}
            maxItems={maxItems}
            busy={busy}
            labels={labels}
            onFiles={onFiles}
          />
        ) : null}
